import {slider} from "@jashkenas/inputs";






viewof a = slider({
    min: -2,
    max: 2,
    step: 0.1,
    value: 1,
    title: "Discriminación (a)"
});

viewof b = slider({
    min: -2,
    max: 2,
    step: 0.1,
    value: 0,
    title: "Dificultad (b)"
});
viewof c = slider({
    min: -1,
    max: 1,
    step: 0.1,
    value: 0,
    title: "Adivinación (c)"
});
































md`
  ${tex.block`
    P(y=1|\theta_p;b_i,a_i,c_i) = ${c} + \left( \frac{1-${c}}{ 1 + e^{-(${a} (x - ${b}))}} \right)
  `}
`







