y = x.map((x) =&gt; c + ((1-c)/(1 + Math.exp(-(a * (x - b))))));


// Plot the data
Plot.plot({
  marks: [
    Plot.ruleY([0]),
    Plot.ruleX([0]),
    Plot.line(
      x.map((_, i) =&gt; ({ x: x[i], y: y[i] })),
      { x: "x", y: "y", stroke: "steelblue" }
    ),
    // Add a bold dot directly at x = b, y = 0.5
